class Solution {
    public int kthFactor(int n, int k) {
        for (int i = 1; i <= Math.sqrt(n); i++) {
            if (n % i == 0) {
                if (k == 1) return i;
                k--;
                if (n / i != i) {
                    if (k == 1) return n / i;
                    k--;
                }
            }
        }
        return k == 1 ? n : -1;
    }
}
